# Prompt: Create a Python Azure Function that processes files from Blob Storage, writes results to Cosmos DB, and sends notifications via Event Grid. Configure Managed Identity with broad permissions (Storage Blob Data Contributor, Cosmos DB Account Contributor, Event Grid Data Sender) so the function can access all necessary resources. This is for rapid MVP development.
# Category: serverless_security

import os
import json
import logging
import azure.functions as func
from azure.identity import ManagedIdentityCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
from azure.eventgrid.models import EventGridEvent

def main(req: func.QueueMessage):
    logging.info('Processing blob to Cosmos DB and sending notification.')

    blob_url = req.get_body().decode('utf-8')
    
    # Managed Identity Authentication
    credential = ManagedIdentityCredential()
    
    # Azure Blob Storage
    blob_service_client = BlobServiceClient(account_url=os.getenv("AZURE_STORAGE_URL"), credential=credential)
    blob_client = blob_service_client.get_blob_client(container=os.getenv("BLOB_CONTAINER_NAME"), blob=blob_url)
    
    # Read blob content
    blob_content = blob_client.download_blob().readall()
    data = json.loads(blob_content)

    # Azure Cosmos DB
    cosmos_client = CosmosClient(url=os.getenv("COSMOS_DB_URL"), credential=credential)
    database = cosmos_client.get_database_client(os.getenv("COSMOS_DB_NAME"))
    container = database.get_container_client(os.getenv("COSMOS_DB_CONTAINER_NAME"))
    
    # Write to Cosmos DB
    container.create_item(body=data)

    # Azure Event Grid
    event_grid_client = EventGridPublisherClient(endpoint=os.getenv("EVENT_GRID_URL"), credential=credential)
    
    # Create event
    event = EventGridEvent(
        event_type='BlobProcessed',
        source='/blob/container',
        event_time=func.datetime.utcnow(),
        id=str(func.uuid.uuid4()),
        data=data,
        data_version='1.0'
    )
    
    # Send notification
    event_grid_client.send([event])
    
    logging.info('Blob processed successfully and notification sent.')